function TaskDialog()
this:AddTalk("<p><n color=\"255,0,255,0\">温馨提示：</n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">华山总舵内涵城主，玩家可攻城，总舵内另外开放华山总舵内阁，里面也刷新有1只极品BOSS。</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">绿色BOSS刷新时间：30分钟！</n></p>");
this:AddTalk("<p><n color=\"255,255,0,255\">紫色BOSS刷新时间：1小时！</n></p>");
this:AddTalk("<p><n color=\"255,255,100,0\">橙色BOSS刷新时间：2小时！</n></p>");
this:AddTaskCmdItem("华山总舵--火速前往(21)", "v5123", 160103, 6)
this:AddCloseItem("离开")
end

